"use strict";(globalThis.webpackChunkai_core_docs=globalThis.webpackChunkai_core_docs||[]).push([[777],{3505(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/vibecoding\u5de5\u5177intro","metadata":{"permalink":"/modern-documentation/blog/vibecoding\u5de5\u5177intro","editUrl":"https://github.com/zweixin798/modern-documentation/tree/main/blog/vibecoding\u5de5\u5177intro.md","source":"@site/blog/vibecoding\u5de5\u5177intro.md","title":"\ud83d\udee0\ufe0f Vibe Coding \u4e3b\u6d41\u5de5\u5177\u7279\u6027\u5168\u96c6","description":"\u672c\u6307\u5357\u65e8\u5728\u5e2e\u52a9\u60a8\u5feb\u901f\u4e86\u89e3\u5f53\u524d\u6700\u70ed\u95e8\u7684 AI \u7f16\u7a0b\uff08Vibe Coding\uff09\u5de5\u5177\uff0c\u5e76\u6839\u636e\u60a8\u7684\u5b9e\u9645\u9700\u6c42\u9009\u62e9\u6700\u5408\u9002\u7684\u201c\u6cd5\u6756\u201d\u3002","date":"2026-03-20T02:22:28.395Z","tags":[],"readingTime":3.24,"hasTruncateMarker":true,"authors":[],"frontMatter":{},"unlisted":false,"nextItem":{"title":"GPT-4o \u6a21\u578b\u4e0a\u7ebf\u66f4\u65b0\u65e5\u5fd7","permalink":"/modern-documentation/blog/gpt-4o-release-notes"}},"content":"\u672c\u6307\u5357\u65e8\u5728\u5e2e\u52a9\u60a8\u5feb\u901f\u4e86\u89e3\u5f53\u524d\u6700\u70ed\u95e8\u7684 AI \u7f16\u7a0b\uff08Vibe Coding\uff09\u5de5\u5177\uff0c\u5e76\u6839\u636e\u60a8\u7684\u5b9e\u9645\u9700\u6c42\u9009\u62e9\u6700\u5408\u9002\u7684\u201c\u6cd5\u6756\u201d\u3002\\n\\n---\\n\\n## 1. \u6838\u5fc3\u5de5\u5177\u6982\u89c8\u8868\\n\\n| \u5de5\u5177\u540d\u79f0 | \u6838\u5fc3\u5b9a\u4f4d | \u63a8\u8350\u6307\u6570 | \u6838\u5fc3 Vibe (\u8c03\u6027) |\\n| :--- | :--- | :--- | :--- |\\n| **Lovable** | \u5168\u6808\u5e94\u7528\u201c\u53d8\u73b0\u201d\u795e\u5668 | \u2b50\u2b50\u2b50\u2b50\u2b50 | \u201c\u6211\u4e0d\u4ec5\u8981\u4ee3\u7801\uff0c\u6211\u8fd8\u8981\u4e00\u4e2a\u80fd\u8dd1\u7684 App\u3002\u201d |\\n| **Cursor** | AI \u589e\u5f3a\u578b\u4ee3\u7801\u7f16\u8f91\u5668 | \u2b50\u2b50\u2b50\u2b50\u2b50 | \u201c\u6211\u662f\u6307\u6325\u5bb6\uff0cAI \u662f\u6211\u7684\u5929\u624d\u526f\u624b\u3002\u201d |\\n| **Bolt.new** | \u6d4f\u89c8\u5668\u5168\u6808\u5f00\u53d1\u73af\u5883 | \u2b50\u2b50\u2b50\u2b50 | \u201c\u968f\u5f00\u968f\u7528\uff0c\u4e00\u53e5\u8bdd\u751f\u6210\u5168\u6808\u7f51\u9875\u3002\u201d |\\n| **v0.dev** | UI/UX \u89c6\u89c9\u5148\u950b | \u2b50\u2b50\u2b50\u2b50 | \u201c\u628a\u6211\u7684\u60f3\u6cd5\u7ffb\u8bd1\u6210\u9876\u7ea7\u7684\u8bbe\u8ba1\u7a3f\u3002\u201d |\\n| **Windsurf** | \u6781\u81f4\u4e0a\u4e0b\u6587\u6d41\u7f16\u8f91\u5668 | \u2b50\u2b50\u2b50\u2b50 | \u201cAI \u61c2\u6211\u5199\u7684\u6bcf\u4e00\u884c\u4ee3\u7801\u548c\u903b\u8f91\u6d41\u3002\u201d |\\n\\n---\\n\\n## 2. \u6df1\u5ea6\u7279\u70b9\u62c6\u89e3\\n\\n### \ud83c\udfa8 Lovable \u2014\u2014 \u201c\u5168\u80fd\u7684\u4ea7\u54c1\u7ecf\u7406\u201d\\nLovable \u662f\u76ee\u524d\u5c06\u201c\u81ea\u7136\u8bed\u8a00\u201d\u8f6c\u5316\u4e3a\u201c\u53ef\u8fd0\u884c\u4ea7\u54c1\u201d\u5b8c\u6210\u5ea6\u6700\u9ad8\u7684\u5de5\u5177\u3002\\n- **\u6570\u636e\u5e93\u96c6\u6210**\uff1a\u539f\u751f\u652f\u6301 Supabase\uff0c\u80fd\u81ea\u52a8\u521b\u5efa\u6570\u636e\u8868\u3001\u5904\u7406\u7528\u6237\u767b\u5f55\u3002\\n- **\u8bbe\u8ba1\u611f\u6781\u5f3a**\uff1a\u751f\u6210\u7684\u754c\u9762\u901a\u5e38\u975e\u5e38\u7cbe\u7f8e\uff0c\u7b26\u5408\u73b0\u4ee3\u5ba1\u7f8e\u3002\\n- **GitHub \u540c\u6b65**\uff1a\u652f\u6301\u4ee3\u7801\u5bfc\u51fa\u548c\u540c\u6b65\uff0c\u4e0d\u9501\u5b9a\u7528\u6237\u3002\\n- **\u9002\u7528\u573a\u666f**\uff1a\u5feb\u901f\u5f00\u53d1 MVP\uff08\u6700\u5c0f\u53ef\u884c\u6027\u4ea7\u54c1\uff09\u3001\u5e26\u540e\u53f0\u6570\u636e\u5b58\u50a8\u7684\u7ba1\u7406\u7cfb\u7edf\u3002\\n\\n### \ud83d\udcbb Cursor \u2014\u2014 \u201c\u7a0b\u5e8f\u5458\u7684\u91cd\u578b\u6b66\u5668\u201d\\n\u57fa\u4e8e VS Code \u6df1\u5ea6\u5b9a\u5236\uff0c\u5b83\u662f\u76ee\u524d\u5f00\u53d1\u8005\u5708\u5b50\u4e2d Vibe Coding \u7684\u7edd\u5bf9\u6807\u6746\u3002\\n- **Composer \u6a21\u5f0f**\uff1a\u53ef\u4ee5\u8de8\u6587\u4ef6\u540c\u65f6\u4fee\u6539\u4ee3\u7801\uff0c\u5b8c\u7f8e\u7406\u89e3\u6574\u4e2a\u9879\u76ee\u7684\u67b6\u6784\u3002\\n- **\u667a\u80fd\u8865\u5168 (Tab)**\uff1a\u9884\u6d4b\u4f60\u4e0b\u4e00\u6b65\u8981\u5199\u4ec0\u4e48\uff0c\u751a\u81f3\u80fd\u6839\u636e\u4f60\u7684\u7f16\u7a0b\u4e60\u60ef\u91cd\u6784\u903b\u8f91\u3002\\n- **\u4ee3\u7801\u5bf9\u8bdd**\uff1a\u4f60\u53ef\u4ee5\u9488\u5bf9\u67d0\u4e00\u6bb5\u7279\u5b9a\u7684 Bug \u75af\u72c2\u201c\u8c03\u6559\u201dAI \u76f4\u5230\u5f7b\u5e95\u4fee\u597d\u3002\\n- **\u9002\u7528\u573a\u666f**\uff1a\u957f\u671f\u7ef4\u62a4\u7684\u590d\u6742\u9879\u76ee\u3001\u7b97\u6cd5\u5f00\u53d1\u3001\u60f3\u8981\u6df1\u5165\u5b66\u4e60\u4ee3\u7801\u903b\u8f91\u7684\u73a9\u5bb6\u3002\\n\\n### \u26a1 Bolt.new \u2014\u2014 \u201c\u6781\u901f\u7684\u539f\u578b\u5b9e\u9a8c\u573a\u201d\\n\u7531 StackBlitz \u51fa\u54c1\uff0c\u5b8c\u5168\u8fd0\u884c\u5728\u6d4f\u89c8\u5668\u4e2d\uff0c\u7701\u53bb\u4e86\u5b89\u88c5\u73af\u5883\u7684\u70e6\u607c\u3002\\n- **\u5168\u6808\u652f\u6301**\uff1a\u4e0d\u4ec5\u662f\u524d\u7aef\uff0c\u8fde Node.js \u540e\u7aef\u4e5f\u80fd\u4e00\u5e76\u751f\u6210\u3002\\n- **WebContainer \u6280\u672f**\uff1a\u76f4\u63a5\u5728\u6d4f\u89c8\u5668\u91cc\u8fd0\u884c\u7ec8\u7aef\u548c\u670d\u52a1\u5668\uff0c\u5b9e\u73b0\u201c\u6240\u89c1\u5373\u6240\u5f97\u201d\u3002\\n- **\u9002\u7528\u573a\u666f**\uff1a\u5feb\u901f\u9a8c\u8bc1\u4e00\u4e2a\u60f3\u6cd5\u3001\u505a\u7b80\u5355\u7684\u81ea\u52a8\u5316\u529e\u516c\u5de5\u5177\u3002\\n\\n### \u2728 v0.dev \u2014\u2014 \u201c\u89c6\u89c9\u4e0e\u4ea4\u4e92\u7684\u5dc5\u5cf0\u201d\\nVercel \u65d7\u4e0b\u7684\u5de5\u5177\uff0c\u4e3b\u8981\u9488\u5bf9 React\u3001Tailwind CSS \u548c Shadcn UI \u7ec4\u4ef6\u5e93\u3002\\n- **\u590d\u5236\u5373\u7528**\uff1a\u751f\u6210\u7684 UI \u7ec4\u4ef6\u4ee3\u7801\u6781\u5176\u5e72\u51c0\uff0c\u53ef\u4ee5\u76f4\u63a5\u8d34\u8fdb\u73b0\u6709\u9879\u76ee\u4e2d\u4f7f\u7528\u3002\\n- **\u7248\u672c\u6f14\u8fdb**\uff1a\u652f\u6301\u5bf9\u540c\u4e00\u754c\u9762\u8fdb\u884c\u591a\u6b21\u7248\u672c\u8fed\u4ee3\uff0c\u5fae\u8c03\u89c6\u89c9\u7ec6\u8282\u548c\u4ea4\u4e92\u624b\u611f\u3002\\n- **\u9002\u7528\u573a\u666f**\uff1a\u9700\u8981\u6781\u9ad8\u989c\u503c\u7684\u5b98\u7f51\u9996\u9875\u3001\u590d\u6742\u7684\u4ea4\u4e92\u5f0f UI \u7ec4\u4ef6\u8bbe\u8ba1\u3002\\n\\n---\\n\\n## 3. \u5982\u4f55\u9009\u62e9\u9002\u5408\u4f60\u7684\u5de5\u5177\uff1f\\n\\n* **\u573a\u666f\u4e00\uff1a\u6211\u5b8c\u5168\u4e0d\u61c2\u6280\u672f\uff0c\u60f3\u505a\u4e00\u4e2a\u80fd\u5b58\u6570\u636e\u7684 App**\\n    * \ud83d\udc49 **\u9996\u9009\uff1aLovable**\\n    * *\u7406\u7531\uff1a\u5b83\u5e2e\u4f60\u5904\u7406\u4e86\u6700\u5934\u75bc\u7684\u6570\u636e\u5e93\u914d\u7f6e\u548c\u670d\u52a1\u5668\u90e8\u7f72\u95ee\u9898\u3002*\\n* **\u573a\u666f\u4e8c\uff1a\u6211\u60f3\u901a\u8fc7 AI \u8f85\u52a9\uff0c\u6b63\u513f\u516b\u7ecf\u5730\u5199\u4e00\u4e2a\u5927\u578b\u7a0b\u5e8f**\\n    * \ud83d\udc49 **\u9996\u9009\uff1aCursor**\\n    * *\u7406\u7531\uff1a\u5b83\u662f\u76ee\u524d\u6700\u5f3a\u529b\u7684\u4ee3\u7801\u52a9\u624b\uff0c\u80fd\u6781\u5927\u63d0\u5347\u4f60\u7684\u751f\u4ea7\u6548\u7387\u3002*\\n* **\u573a\u666f\u4e09\uff1a\u6211\u5c31\u60f3\u505a\u4e00\u4e2a\u6f02\u4eae\u7684\u524d\u7aef\u9875\u9762\uff0c\u4e0d\u6d89\u53ca\u590d\u6742\u540e\u53f0\u903b\u8f91**\\n    * \ud83d\udc49 **\u9996\u9009\uff1av0.dev**\\n    * *\u7406\u7531\uff1a\u5ba1\u7f8e\u6781\u5ea6\u5728\u7ebf\uff0c\u751f\u6210\u7684\u7ec4\u4ef6\u4ee3\u7801\u8d28\u91cf\u7b26\u5408\u5de5\u4e1a\u7ea7\u6807\u51c6\u3002*\\n\\n---\\n\\n## 4. Vibe Coding \u6210\u529f\u4e09\u8981\u7d20\\n\\n\u65e0\u8bba\u4f60\u9009\u62e9\u54ea\u4e2a\u5de5\u5177\uff0c\u8bf7\u8bb0\u4f4f\u8fd9\u4e2a\u4e07\u80fd\u516c\u5f0f\uff1a\\n\\n$$\u7ed3\u679c = \u7ed3\u6784\u5316 Prompt + \u6301\u7eed\u7684\u53cd\u9988\u8fed\u4ee3 + \u57fa\u672c\u7684\u903b\u8f91\u5224\u65ad$$\\n\\n1.  **\u7ed3\u6784\u5316 Prompt**\uff1a\u6e05\u6670\u5730\u544a\u8bc9 AI \u76ee\u6807\u3001\u8f93\u5165\u3001\u8f93\u51fa\u548c\u5177\u4f53\u7684\u9650\u5236\u6761\u4ef6\u3002\\n2.  **\u6301\u7eed\u8fed\u4ee3**\uff1a\u4e0d\u8981\u6307\u671b AI \u4e00\u6b21\u5c31\u80fd\u5199\u5bf9\uff0c\u901a\u8fc7\u4e0d\u65ad\u201c\u53cd\u9988-\u4fee\u6b63\u201d\u8ba9 AI \u903c\u8fd1\u4f60\u7684\u60f3\u6cd5\u3002\\n3.  **\u903b\u8f91\u5224\u65ad**\uff1a\u4f60\u867d\u7136\u4e0d\u9700\u8981\u7cbe\u901a\u4ee3\u7801\u8bed\u6cd5\uff0c\u4f46\u4f60\u8981\u80fd\u770b\u61c2\u529f\u80fd\u662f\u5426\u8dd1\u901a\uff0c\u903b\u8f91\u662f\u5426\u5408\u7406\u3002\\n\\n---\\n\\n> **\ud83d\udca1 \u5efa\u8bae\uff1a** \u5982\u679c\u4f60\u662f\u521a\u5165\u95e8\u7684 Vibe Coder\uff0c\u53ef\u4ee5\u5148\u4ece **Lovable** \u6216 **Bolt.new** \u5f00\u59cb\u611f\u53d7\u201c\u4e00\u79d2\u4e0a\u7ebf\u201d\u7684\u5feb\u4e50\uff0c\u518d\u9010\u6b65\u8fc7\u6e21\u5230 **Cursor** \u8fdb\u884c\u6df1\u5ea6\u521b\u4f5c\u3002\\n\\n`\x3c!-- truncate --\x3e`"},{"id":"gpt-4o-release-notes","metadata":{"permalink":"/modern-documentation/blog/gpt-4o-release-notes","editUrl":"https://github.com/zweixin798/modern-documentation/tree/main/blog/blog:2026-03-19-building-ai-dev-portal.md","source":"@site/blog/blog:2026-03-19-building-ai-dev-portal.md","title":"GPT-4o \u6a21\u578b\u4e0a\u7ebf\u66f4\u65b0\u65e5\u5fd7","description":"\u6211\u4eec\u5df2\u5728 AI Core \u5e73\u53f0\u6b63\u5f0f\u4e0a\u7ebf GPT-4o \u7cfb\u5217\u6a21\u578b\uff0c\u5e76\u540c\u6b65\u589e\u5f3a\u4e86\u591a\u6a21\u6001\u4e0e\u51fd\u6570\u8c03\u7528\u4f53\u9a8c\u3002","date":"2026-03-19T00:00:00.000Z","tags":[{"inline":true,"label":"changelog","permalink":"/modern-documentation/blog/tags/changelog"}],"readingTime":1,"hasTruncateMarker":true,"authors":[{"name":"Weixin Zhang","title":"AI Enthusiast / Graduate Student","url":"https://github.com/zweixin798","imageURL":"https://github.com/zweixin798.png","key":"zweixin798","page":null}],"frontMatter":{"slug":"gpt-4o-release-notes","title":"GPT-4o \u6a21\u578b\u4e0a\u7ebf\u66f4\u65b0\u65e5\u5fd7","authors":["zweixin798"],"tags":["changelog"]},"unlisted":false,"prevItem":{"title":"\ud83d\udee0\ufe0f Vibe Coding \u4e3b\u6d41\u5de5\u5177\u7279\u6027\u5168\u96c6","permalink":"/modern-documentation/blog/vibecoding\u5de5\u5177intro"}},"content":"\u6211\u4eec\u5df2\u5728 **AI Core** \u5e73\u53f0\u6b63\u5f0f\u4e0a\u7ebf **GPT-4o** \u7cfb\u5217\u6a21\u578b\uff0c\u5e76\u540c\u6b65\u589e\u5f3a\u4e86\u591a\u6a21\u6001\u4e0e\u51fd\u6570\u8c03\u7528\u4f53\u9a8c\u3002\\n\\n\x3c!-- truncate --\x3e\\n\\n## \u65b0\u589e\u80fd\u529b\\n\\n- **\u66f4\u5f3a\u7684\u5bf9\u8bdd\u8d28\u91cf**\uff1a\u5728\u957f\u4e0a\u4e0b\u6587\u4e0b\u7684\u6307\u4ee4\u9075\u5faa\u4e0e\u8868\u8fbe\u66f4\u7a33\u5b9a\u3002\\n- **\u66f4\u987a\u6ed1\u7684\u5de5\u5177\u8c03\u7528**\uff1a\u51fd\u6570\u8c03\u7528\uff08tool calls\uff09\u8f93\u51fa\u66f4\u7ed3\u6784\u5316\uff0c\u66f4\u9002\u5408\u4e0e\u5de5\u4f5c\u6d41\u7f16\u6392\u7ed3\u5408\u3002\\n- **\u66f4\u53cb\u597d\u7684\u5de5\u7a0b\u96c6\u6210**\uff1aAPI \u517c\u5bb9 `POST /v1/chat/completions`\uff0c\u66f4\u6613\u8fc1\u79fb\u4e0e\u66ff\u6362\u3002\\n\\n## \u517c\u5bb9\u6027\u8bf4\u660e\\n\\n- **API \u8def\u5f84**\uff1a\u4fdd\u6301 `/v1/chat/completions`\u3002\\n- **\u53c2\u6570**\uff1a`messages`\u3001`temperature`\u3001`max_tokens` \u7b49\u4fdd\u6301\u4e00\u81f4\uff1b\u65b0\u589e/\u589e\u5f3a `tools` \u4e0e `tool_choice` \u7684\u4f7f\u7528\u4f53\u9a8c\u3002\\n- **\u54cd\u5e94**\uff1a\u5728\u89e6\u53d1\u5de5\u5177\u8c03\u7528\u65f6\uff0c`finish_reason` \u53ef\u80fd\u4e3a `tool_calls`\uff0c\u5e76\u8fd4\u56de `tool_calls` \u7ed3\u6784\u3002\\n\\n## \u5efa\u8bae\u5347\u7ea7\u65b9\u5f0f\\n\\n1. \u5148\u5728\u7070\u5ea6\u73af\u5883\u5207\u6362 `model` \u4e3a `gpt-4o` \u6216 `gpt-4o-mini`\u3002\\n2. \u5bf9\u5173\u952e\u4efb\u52a1\u542f\u7528 **\u7ed3\u6784\u5316\u8f93\u51fa**\uff08JSON Schema\uff09\u5e76\u6dfb\u52a0\u6821\u9a8c\u3002\\n3. \u82e5\u4f60\u4f7f\u7528 RAG\uff0c\u8bf7\u540c\u65f6\u76d1\u63a7\u201c\u68c0\u7d22\u547d\u4e2d\u7387\u201d\u548c\u201c\u5f15\u7528\u4e00\u81f4\u6027\u201d\uff0c\u907f\u514d\u9ad8\u53ec\u56de\u4f46\u4f4e\u76f8\u5173\u5bfc\u81f4\u8bef\u7b54\u3002\\n\\n## \u4e0b\u4e00\u6b65\\n\\n- \u6211\u4eec\u4f1a\u5728\u540e\u7eed\u7248\u672c\u8865\u9f50\u66f4\u591a SDK \u793a\u4f8b\u4e0e\u6700\u4f73\u5b9e\u8df5\uff08Prompt \u89c4\u8303\u3001\u5de5\u5177\u8c03\u7528\u6a21\u5f0f\u3001RAG \u8bc4\u6d4b\u65b9\u6cd5\uff09\u3002"}]}}')}}]);